<div class="d-flex justify-content-between align-items-center mb-3"><h5>Clientes</h5></div>
<form class="row g-2 mb-3" method="get"><div class="col-md-4"><input class="form-control" name="q" placeholder="Buscar por nombre/documento/teléfono"></div><div class="col"><button class="btn btn-outline-secondary">Buscar</button></div></form>
<div class="card mb-3"><div class="card-body"><form method="post" action="/customers/create" class="row g-2"><?= csrf_field() ?><div class="col-md-2"><input required name="first_name" class="form-control" placeholder="Nombres"></div><div class="col-md-2"><input required name="last_name" class="form-control" placeholder="Apellidos"></div><div class="col-md-2"><input name="document_number" class="form-control" placeholder="RUT/Doc"></div><div class="col-md-2"><input name="phone" class="form-control" placeholder="Teléfono"></div><div class="col-md-2"><input name="email" class="form-control" placeholder="Correo"></div><div class="col-md-2"><button class="btn btn-dark w-100">Guardar</button></div></form></div></div>
<div class="table-responsive"><table class="table table-striped"><tr><th>ID</th><th>Cliente</th><th>Documento</th><th>Teléfono</th><th>Ciudad</th><th>Estado</th></tr><?php foreach ($customers as $c): ?><tr><td><?= e((string)$c['id']) ?></td><td><?= e($c['first_name'] . ' ' . $c['last_name']) ?></td><td><?= e((string)$c['document_number']) ?></td><td><?= e((string)$c['phone']) ?></td><td><?= e((string)$c['city']) ?></td><td><span class="badge <?= (int)$c['status'] === 1 ? 'bg-success':'bg-secondary' ?>"><?= (int)$c['status'] === 1 ? 'Activo':'Inactivo' ?></span></td></tr><?php endforeach; ?></table></div>
